SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_pivot."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(coalesce(ts_pivot."up__out.electricity.total.energy_consumption", ts_pivot."bs__out.electricity.total.energy_consumption") * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.electricity.total.energy_consumption", 0) - coalesce(coalesce(ts_pivot."up__out.electricity.total.energy_consumption", ts_pivot."bs__out.electricity.total.energy_consumption"), 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", sum(ts_pivot."bs__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__baseline", sum(coalesce(ts_pivot."up__out.natural_gas.total.energy_consumption", ts_pivot."bs__out.natural_gas.total.energy_consumption") * bs.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(ts_pivot."bs__out.natural_gas.total.energy_consumption", 0) - coalesce(coalesce(ts_pivot."up__out.natural_gas.total.energy_consumption", ts_pivot."bs__out.natural_gas.total.energy_consumption"), 0)) * bs.weight) AS "natural_gas.total.energy_consumption__savings" FROM (SELECT ts_flat.bldg_id AS bldg_id, ts_flat.timestamp AS timestamp, sum(ts_flat."_v__out.electricity.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 0) AS "bs__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.electricity.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 1) AS "up__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 0) AS "bs__out.natural_gas.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") FILTER (WHERE ts_flat.upgrade = 1) AS "up__out.natural_gas.total.energy_consumption" FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, date_trunc('year', date_add('second', -900, resstock_2024_amy2018_release_2_by_state_vu.timestamp)) AS timestamp, resstock_2024_amy2018_release_2_by_state_vu.upgrade AS upgrade, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption", resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS "_v__out.natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (0, 1) AND resstock_2024_amy2018_release_2_by_state_vu.state IN ('CO', 'WY')) AS ts_flat GROUP BY ts_flat.bldg_id, ts_flat.timestamp) AS ts_pivot JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_pivot.bldg_id AND bs.upgrade = 0 GROUP BY 1 ORDER BY 1